changeSet.sql:
DELETE FROM clinlims.notebook_page
WHERE title = 'Reference & SOP Module'
AND notebook_id IN (
    SELECT id FROM clinlims.notebook WHERE title = 'Pathology Laboratory'
);

UPDATE clinlims.notebook_page
SET content = REPLACE(content, '"nextPage": "Reference & SOP Module"', '"nextPage": null')
WHERE title = 'Disposal & Archiving'
AND notebook_id IN (
    SELECT id FROM clinlims.notebook WHERE title = 'Pathology Laboratory'
);

DELETE FROM clinlims.workflow_page_template
WHERE workflow_category = 'PATHOLOGY'
AND name = 'Reference & SOP Module';
